<script setup lang="ts">import{ref,nextTick}from'vue';import{ArrowUp,Paperclip,Sparkles}from'lucide-vue-next';defineProps<{disabled?:boolean}>();const emit=defineEmits<{send:[value:string]}>();const text=ref(''),input=ref<HTMLTextAreaElement>();function send(){const v=text.value.trim();if(!v)return;emit('send',v);text.value='';nextTick(()=>{if(input.value)input.value.style.height='24px'})}function resize(e:Event){const el=e.target as HTMLTextAreaElement;el.style.height='24px';el.style.height=Math.min(el.scrollHeight,160)+'px'}function key(e:KeyboardEvent){if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();send()}}</script>
<template><div class="composer" :class="{disabled}"><textarea ref="input" v-model="text" @input="resize" @keydown="key" :disabled="disabled" rows="1" placeholder="向知识库提问，Shift + Enter 换行…" aria-label="消息输入框"></textarea><div class="composer-actions"><button class="icon-btn" title="附件将在下一版本支持"><Paperclip/></button><span><Sparkles/>基于知识库回答</span><button class="send" @click="send" :disabled="!text.trim()||disabled" aria-label="发送"><ArrowUp/></button></div></div></template>
